import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read the entire line instead of just a token

        int maxLength = Math.min(name.length(), 10); // Limit the input to buffer size
        char[] buffer = new char[maxLength];

        // Copy user input into the buffer
        name.getChars(0, maxLength, buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
